<?php
if (!defined('SDS_PERPUSTAKAAN_APP')) { http_response_code(403); exit('Akses langsung tidak diizinkan.'); }
$page='notifikasi';require __DIR__.'/../partials/bootstrap.php';if(empty($perpusAccess['allowed']))return;$message='';$error='';
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){try{perpus_check_csrf();$action=(string)($_POST['action']??'');if(!$perpusIsAdmin)throw new RuntimeException('Hanya admin Perpustakaan yang dapat menjalankan pengingat.');if($action==='process'){$sum=sds_perpus_process_due_reminders($conn,1000);$message='Pengingat selesai: '.(int)$sum['created'].' notifikasi baru, '.(int)$sum['skipped'].' sudah pernah diproses, dan '.(int)$sum['expired'].' reservasi kedaluwarsa.';}elseif($action==='token'){$token=bin2hex(random_bytes(24));sds_perpus_save_setting($conn,'reminder_token',$token,'Token endpoint pengingat terjadwal');$message='Token endpoint pengingat berhasil dibuat ulang.';}else throw new RuntimeException('Aksi tidak dikenal.');}catch(Throwable $e){$error=$e->getMessage();}}
$settings=[];$r=$conn->query('SELECT kode,nilai FROM perpus_pengaturan');while($r&&($x=$r->fetch_assoc()))$settings[$x['kode']]=$x['nilai'];$token=(string)($settings['reminder_token']??'');
$stats=['baru'=>0,'hari_ini'=>0,'terlambat'=>0,'log_hari_ini'=>0];$q=$conn->query("SELECT COUNT(*) total FROM perpus_notifikasi WHERE status='baru'");if($q)$stats['baru']=(int)$q->fetch_assoc()['total'];$q=$conn->query("SELECT COUNT(*) total FROM perpus_notifikasi WHERE DATE(created_at)=CURDATE()");if($q)$stats['hari_ini']=(int)$q->fetch_assoc()['total'];$q=$conn->query("SELECT COUNT(*) total FROM perpus_peminjaman_detail WHERE status='dipinjam' AND tanggal_jatuh_tempo<CURDATE()");if($q)$stats['terlambat']=(int)$q->fetch_assoc()['total'];$q=$conn->query("SELECT COUNT(*) total FROM perpus_pengingat_log WHERE tanggal_proses=CURDATE()");if($q)$stats['log_hari_ini']=(int)$q->fetch_assoc()['total'];
$rows=[];$r=$conn->query("SELECT n.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan FROM perpus_notifikasi n JOIN perpus_anggota a ON a.id=n.anggota_id ORDER BY n.id DESC LIMIT 300");while($r&&($x=$r->fetch_assoc())){$x['profile']=sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x);$rows[]=$x;}
$endpoint=$token!==''?sds_base_url('perpustakaan/reminder.php?token='.rawurlencode($token)):'';require __DIR__.'/../partials/master_page_style.php';
?>
<div class="sds-master-page"><div class="sds-hero"><div><h2>Notifikasi & Pengingat</h2><p>Bangun notifikasi internal untuk jatuh tempo, keterlambatan, dan status reservasi.</p></div><div class="sds-hero-actions"><form method="post"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="process"><button class="btn btn-primary"><i data-feather="send" class="me-1"></i>Proses Pengingat Sekarang</button></form></div></div><?php if($message):?><div class="alert alert-success"><?=perpus_h($message)?></div><?php endif;?><?php if($error):?><div class="alert alert-danger"><?=perpus_h($error)?></div><?php endif;?>
<div class="sds-stat-grid"><div class="sds-stat-card"><small>Belum Dibaca</small><strong><?=number_format($stats['baru'],0,',','.')?></strong><span>Notifikasi anggota</span></div><div class="sds-stat-card"><small>Dibuat Hari Ini</small><strong><?=number_format($stats['hari_ini'],0,',','.')?></strong><span>Semua jenis pesan</span></div><div class="sds-stat-card"><small>Pinjaman Terlambat</small><strong><?=number_format($stats['terlambat'],0,',','.')?></strong><span>Perlu ditindaklanjuti</span></div><div class="sds-stat-card"><small>Pengingat Diproses</small><strong><?=number_format($stats['log_hari_ini'],0,',','.')?></strong><span>Hari ini</span></div></div>
<div class="row g-3"><div class="col-xl-8"><div class="card card-outline card-primary"><div class="card-header"><h5>Riwayat Notifikasi Anggota</h5><span class="small text-muted">Status dibaca berubah saat anggota membuka Akun Saya</span></div><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Anggota</th><th>Notifikasi</th><th>Status</th><th>Waktu</th></tr></thead><tbody><?php if(!$rows):?><tr><td colspan="4" class="text-center text-muted py-4">Belum ada notifikasi.</td></tr><?php endif;?><?php foreach($rows as $n):$p=$n['profile'];?><tr><td><strong><?=perpus_h($p['nama'])?></strong><div class="small text-muted"><?=perpus_h($n['nomor_anggota'])?> · <?=perpus_h($p['unit'])?></div></td><td><strong><?=perpus_h($n['judul'])?></strong><div class="small text-muted"><?=perpus_h($n['pesan'])?></div></td><td><span class="badge <?=$n['status']==='baru'?'bg-warning text-dark':'bg-success'?>"><?=perpus_h(ucfirst($n['status']))?></span></td><td><?=date('d/m/Y H:i',strtotime($n['created_at']))?></td></tr><?php endforeach;?></tbody></table></div></div></div><div class="col-xl-4"><div class="card card-outline card-info"><div class="card-header"><h5>Otomasi Pengingat</h5></div><div class="card-body"><p class="text-muted">Endpoint dapat dipanggil satu kali setiap hari melalui Cron Job hosting.</p><?php if($endpoint):?><label class="form-label">URL Cron</label><textarea class="form-control font-monospace" rows="4" readonly><?=perpus_h($endpoint)?></textarea><?php else:?><div class="alert alert-warning">Token cron belum dibuat.</div><?php endif;?><form method="post" class="mt-3"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="token"><button class="btn btn-outline-primary w-100"><i data-feather="key" class="me-1"></i><?= $token!==''?'Buat Ulang':'Buat' ?> Token Cron</button></form><div class="small text-muted mt-3">Notifikasi saat ini bersifat internal dan ditampilkan pada halaman Akun Saya di OPAC.</div></div></div><div class="card card-outline card-success"><div class="card-header"><h5>Kiosk Kunjungan</h5></div><div class="card-body"><a class="btn btn-success w-100" target="_blank" href="<?=perpus_h(sds_base_url('perpustakaan/kiosk/'))?>"><i data-feather="monitor" class="me-1"></i>Buka Kiosk</a></div></div></div></div></div>
